def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = float('inf')
            continue
        score = 0
        decay = 1.0
        for step in range(5):
            if ratio < 0.01 and step > 0:
                break
            increment = (np.sqrt(ratio + 0.1) * decay) / (step + 1)
            score += increment
            ratio *= 0.85
            decay *= 0.9
        if score > 2:
            penalty = 0
            for digit in str(int(capacity)):
                penalty += int(digit)
                if penalty > 10:
                    break
            priorities[i] = score * (10 + penalty / 2)
        elif score > 1:
            priorities[i] = score * 8
        else:
            priorities[i] = score * 2
        if int(capacity) % 2 == 0:
            priorities[i] *= 0.95
        else:
            priorities[i] *= 1.05
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        min_priority = 1
    else:
        min_priority = np.min(finite_priorities)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = min_priority * 150
    total = np.sum(priorities[np.isfinite(priorities)])
    if total > 0:
        priorities[np.isfinite(priorities)] /= total
    return priorities
